import java.util.*;

public class ArrayList implements Comparable<ArrayList> {
    private String id;
    public ArrayList(String id) { this.id = id; }

    public String getId() { return id; }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        ArrayList that = (ArrayList) o;
        return Objects.equals(id, that.id);
    }

    @Override
    public int hashCode() { return Objects.hash(id); }

    @Override
    public int compareTo(ArrayList o) { return this.id.compareTo(o.id); }

    public static void main(String[] args) {
        Set<ArrayList> set = new HashSet<>();
        set.add(new ArrayList("A002"));
        set.add(new ArrayList("A001"));
        set.add(new ArrayList("A002")); // duplicate

        List<ArrayList> list = new ArrayList<>(set);
        Collections.sort(list);
        for (ArrayList item : list) System.out.println(item.getId());
    }
}
